// End-to-end test for critique_design — uses an image generated by test-imagen first,
// or a known public architectural photo if no GCS image is available.
// Run: node test/test-critique.js [gs://... or https://...]
import { GoogleAuth } from "google-auth-library";

const PROJECT      = "my-system-488711";
const GEMINI_MODEL = "gemini-2.5-flash";
const REGION       = "us-central1";

const auth = new GoogleAuth({ scopes: ["https://www.googleapis.com/auth/cloud-platform"] });

async function authHeader() {
  const client = await auth.getClient();
  const token  = await client.getAccessToken();
  return `Bearer ${token.token}`;
}

async function fetchImageAsBase64(url) {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`HTTP ${res.status} fetching ${url}`);
  const buf      = Buffer.from(await res.arrayBuffer());
  const mimeType = res.headers.get("content-type")?.split(";")[0] ?? "image/jpeg";
  return { base64: buf.toString("base64"), mimeType };
}

async function run() {
  const imageSource = process.argv[2] ??
    // Wikimedia Commons: Therme Vals by Peter Zumthor — a relevant architectural reference.
    "https://upload.wikimedia.org/wikipedia/commons/thumb/5/52/Therme_Vals-_Peter_Zumthor%2C_Vals%2C_Grisons%2C_Switzerland_%28Ank_Kumar%29_09.jpg/1280px-Therme_Vals-_Peter_Zumthor%2C_Vals%2C_Grisons%2C_Switzerland_%28Ank_Kumar%29_09.jpg";

  console.log("▶  critique_design — end-to-end test");
  console.log(`   model  : ${GEMINI_MODEL}`);
  console.log(`   region : ${REGION}`);
  console.log(`   image  : ${imageSource.slice(0, 80)}…\n`);

  const briefExcerpt = `
Tectonic Studio: Every material decision is a documented argument.
The site must feel exacting, quiet, and material — as if the brand would sooner lose a
commission than agree to a brief they believe is misconceived.
Signature moment: when a visitor dwells on a material photograph for four seconds,
the image desaturates and a verbatim sentence from the original client brief appears
at the bottom edge.
  `.trim();

  // Build parts
  const parts = [];

  if (imageSource.startsWith("gs://")) {
    parts.push({
      fileData: { mimeType: "image/jpeg", fileUri: imageSource },
    });
  } else {
    const { base64, mimeType } = await fetchImageAsBase64(imageSource);
    parts.push({ inlineData: { mimeType, data: base64 } });
  }

  parts.push({
    text: `You are a senior digital creative director reviewing a design asset.
Evaluate the image above with precision and candour — no diplomatic hedging.

PROJECT BRIEF EXCERPT (evaluate the design against this):
${briefExcerpt}

Pay particular attention to: materiality, lighting quality, spatial hierarchy, brand alignment.

Score 0–100 where:
  90–100 = ships immediately, award-worthy
  75–89  = strong, one meaningful revision needed
  60–74  = competent foundation, two or three specific issues
  40–59  = significant rework needed
  0–39   = fundamental problems, reconsider direction

Return a JSON object matching the schema provided.`,
  });

  const responseSchema = {
    type: "OBJECT",
    properties: {
      score:           { type: "INTEGER" },
      headline:        { type: "STRING" },
      strengths:       { type: "ARRAY", items: { type: "STRING" } },
      improvements: {
        type: "ARRAY",
        items: {
          type: "OBJECT",
          properties: {
            area:  { type: "STRING" },
            issue: { type: "STRING" },
            fix:   { type: "STRING" },
          },
          required: ["area", "issue", "fix"],
        },
      },
      brief_alignment: { type: "STRING" },
      verdict:         { type: "STRING" },
    },
    required: ["score", "headline", "strengths", "improvements", "verdict"],
  };

  const t0  = Date.now();
  const url = `https://${REGION}-aiplatform.googleapis.com/v1/projects/${PROJECT}/locations/${REGION}/publishers/google/models/${GEMINI_MODEL}:generateContent`;

  const res = await fetch(url, {
    method: "POST",
    headers: { Authorization: await authHeader(), "Content-Type": "application/json" },
    body: JSON.stringify({
      contents: [{ role: "user", parts }],
      generationConfig: {
        responseMimeType: "application/json",
        responseSchema,
        temperature: 0.2,
      },
    }),
  });

  const json = await res.json();
  if (!res.ok) {
    console.error("✗  API error:", json?.error?.message ?? JSON.stringify(json));
    process.exit(1);
  }

  const raw     = json.candidates?.[0]?.content?.parts?.[0]?.text;
  const elapsed = ((Date.now() - t0) / 1000).toFixed(1);

  if (!raw) {
    console.error("✗  No content in response:", JSON.stringify(json, null, 2));
    process.exit(1);
  }

  const critique = JSON.parse(raw);

  console.log(`   ✓  Gemini responded in ${elapsed}s`);
  console.log(`\n   Score    : ${critique.score}/100`);
  console.log(`   Headline : ${critique.headline}`);
  console.log(`\n   Strengths:`);
  critique.strengths.forEach(s => console.log(`     • ${s}`));
  console.log(`\n   Improvements:`);
  critique.improvements.forEach(i =>
    console.log(`     [${i.area}] ${i.issue}\n       → ${i.fix}`)
  );
  if (critique.brief_alignment) {
    console.log(`\n   Brief alignment: ${critique.brief_alignment}`);
  }
  console.log(`\n   Verdict  : ${critique.verdict}`);
  console.log("\n✓  critique_design test passed");
}

run().catch(err => { console.error("✗  Unhandled error:", err.message); process.exit(1); });
